def diffWaysToCompute(expression):
    memo = {}
    def helper(s):
        if s in memo: return memo[s]
        res = []
        for i, char in enumerate(s):
            if char in "+-*":
                left = helper(s[:i])
                right = helper(s[i+1:])
                for l in left:
                    for r in right:
                        if char == "+": res.append(l + r)
                        elif char == "-": res.append(l - r)
                        else: res.append(l * r)
        if not res: res = [int(s)]
        memo[s] = res
        return res
    return helper(expression)

